import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { sendOtp } from "../services/api"; // your existing API
import { Box, Button, Container, TextField, Typography, Alert } from "@mui/material";

export default function RiderLogin() {
  const [mobile, setMobile] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSendOtp = async () => {
    setError("");
    setSuccess("");

    // ✅ Validate 10-digit mobile number
    const mobilePattern = /^\d{10}$/;
    if (!mobilePattern.test(mobile)) {
      setError("Enter a valid 10-digit mobile number");
      return;
    }

    try {
      setLoading(true);
      const res = await sendOtp(mobile, "rider");
      if (res.data.success) {
        setSuccess("OTP sent successfully! Check your mobile.");
        // navigate to OTP page if needed, or step 2
      } else {
        setError(res.data.message || "Failed to send OTP");
      }
    } catch (err) {
      // ✅ Show proper message if rider is pending approval
      setError(err.response?.data?.message || "Server error while sending OTP");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Box sx={{ mt: 8, p: 4, border: "1px solid #ccc", borderRadius: 2, textAlign: "center" }}>
        <Typography variant="h5" gutterBottom>
          Rider Login
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <TextField
          fullWidth
          label="Mobile Number"
          variant="outlined"
          margin="normal"
          value={mobile}
          onChange={(e) => setMobile(e.target.value)}
        />

        <Button
          fullWidth
          variant="contained"
          onClick={handleSendOtp}
          disabled={loading}
          sx={{ mt: 2, bgcolor: "black", "&:hover": { bgcolor: "#333" } }}
        >
          {loading ? "Sending..." : "Send OTP"}
        </Button>

        <Box sx={{ mt: 3 }}>
          <Typography variant="body2">
            Don’t have an account? <Link to="/rider-register">Sign Up</Link>
          </Typography>
          <Typography variant="body2" sx={{ mt: 1 }}>
            Are you a User? <Link to="/login">Login as User</Link>
          </Typography>
        </Box>
      </Box>
    </Container>
  );
}
